import{_ as e,o as a,c as o,ag as i}from"./chunks/framework.ePeAWSvT.js";const n="/assets/datahub-action-edit-maps.CaXqTyh7.png",s="/assets/datahub-map-preview.CP4XR2_u.png",m=JSON.parse('{"title":"Action Mapping","description":"","frontmatter":{},"headers":[],"relativePath":"guide/datahub-action-mapping.md","filePath":"guide/datahub-action-mapping.md"}'),r={name:"guide/datahub-action-mapping.md"};function l(d,t,p,h,c,g){return a(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="action-mapping" tabindex="-1">Action Mapping <a class="header-anchor" href="#action-mapping" aria-label="Permalink to &quot;Action Mapping&quot;">​</a></h1><p>Once all of the Endpoints are added to the Data Hub, you need to map each Endpoint Action, tying all of your Schema Definitions to the Connectors by mapping how the data needs to flow between systems. Most Connectors utilize JSON or XML language to &quot;talk&quot; to the Common Model; however, the types of maps are dependent on the type of connector data you are mapping to (JSON, XML, SQL, and Delimited Files). The Connector Property field must match the exact naming and language of the Connector.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>When you open the Mapping screen, you will see a black code box on the left, with an open area to add properties on the right. The code box will display the details as you create the Mapping. The Connector data is always shown on the left side in blue text, while the Common Model data (Schema Definitions) is shown on the right side in purple text. The arrows between the Connector and Common Model indicate the direction data will flow. The arrow will always point towards the application receiving the data. Fixed values will always show in orange text.</p><p>For example, when a connection is publishing data to the Common Model via JSON protocols, the arrow will point from the Connector to the Common Model. However, when working on the subscribing side, the arrow will point towards the Connector -- since the data is flowing from the Common Model to the Connector.</p></div><div class="tip custom-block"><p class="custom-block-title">Advanced Tool</p><p>Advanced users can view, and in some cases modify, the underlying configuration that is fed into the engine. To access code view, select the code icon in the top right corner. See <a href="./datahub-code-view.html">Code View</a> for more details.</p></div><div class="warning custom-block"><p class="custom-block-title">NOTES</p><ul><li>The following instructions for Mapping Endpoint Actions are generically written for JSON protocols; however, each protocol will have its own distinct appearance and follow its own standards (e.g. JSON will present within curly brackets, while XML will present within square brackets).</li><li>Additionally, these instructions guide you through the addition of a Simple Property. However, you will select the most applicable Property Type for your protocol and data; then, loosely follow the same instructions.</li><li>If a Template was used to configure the Endpoint, some Mapping will be pre-populated; you can edit the Mapping as needed to achieve the desired syncs.</li><li><strong>For detailed descriptions of mappable properties for each protocol</strong>, see the <a href="#mapping-properties-of-endpoint-actions-per-protocol">Mapping Properties of Endpoint Actions per Protocol</a> section below.</li></ul></div><h2 id="map-endpoint-actions" tabindex="-1">Map Endpoint Actions <a class="header-anchor" href="#map-endpoint-actions" aria-label="Permalink to &quot;Map Endpoint Actions&quot;">​</a></h2><p><img src="'+n+`" alt="Edit Endpoint Action Maps"></p><ol><li><p>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</p></li><li><p>Select the appropriate <strong>Data Hub</strong>; then, select the appropriate parent <strong>Endpoint</strong>.</p></li><li><p>Ensure you are on the <strong>Data Source</strong> tab, and select the appropriate <strong>Event</strong>.</p></li><li><p>Select the <strong>menu</strong> icon &gt; <strong>Edit Maps</strong>.</p></li><li><p>As needed, select <strong>+ Add Map Group</strong>.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>If the Endpoint was configured using a Template, you will not see this screen as some Mapping will be pre-populated; you can continue to the next step.</p></div></li><li><p>Select the <strong>top row</strong> of the code box on the left side.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>If you are simply adding a map to the route, then select the top line in the code box. However, when you want to add a map to a specific action (e.g. Saves), select that line in the left pane (specifically, where on the payload you want to add your map).</p></div></li><li><p>Select how to map the data via the <strong>Add Element</strong> selectors and, as needed, toggle ON <strong>Make List</strong>. Make List allows you to add a list structure instead of an object structure when configuring the mapping payload.</p><div class="warning custom-block"><p class="custom-block-title">NOTES</p><ul><li>Only mappable options will be displayed based on your configured Endpoints.</li><li>You can add one or more of the Element types to a single Map.</li><li>For detailed descriptions of mappable properties for each protocol, see the <a href="#mapping-properties-of-endpoint-actions-per-protocol">Mapping Properties of Endpoint Actions per Protocol</a> section below.</li></ul></div></li><li><p>Depending on the method, select a <strong>Central Property</strong> and/or define the <strong>Connector Property</strong>. Or, when mapping a File connector, enter a <strong>Field Position</strong> and <strong>Field Width</strong>.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>The <strong>Field Position</strong> refers to the character position the field starts on; the <strong>Field Width</strong> refers to how many characters are in the data field you are syncing.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><ul><li>To delete a map property, select the <strong>delete</strong> icon in that row of the code.</li><li>To adjust the order of a Mapping element, select the <strong>up</strong> or <strong>down arrow</strong> in that row of the code.</li></ul></div></li><li><p>As needed, <strong>adapt</strong> the data.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>It is possible to adapt the data as it is published to the Common Model or as an Endpoint subscribes to that data. For additional information and instructions, see the <a href="./datahub-data-adaptation.html">Data Adaptation</a> section.</p></div></li><li><p>Repeat the previous steps to construct all of the necessary Mapping.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>While Mapping, select <strong>Save</strong> as needed; doing so will not close the window.</p></div></li><li><p>When finished, select <strong>Save</strong>; then select <strong>Cancel</strong> to close the window.</p></li></ol><h2 id="mapping-related-data-properties" tabindex="-1">Mapping Related Data Properties <a class="header-anchor" href="#mapping-related-data-properties" aria-label="Permalink to &quot;Mapping Related Data Properties&quot;">​</a></h2><p>When mapping a <strong>save/subscribe</strong> action, the Central Property picker includes properties from related entities — not just the entity&#39;s own schema. These are properties that have been flagged as <a href="./reference-related-data.html">Related Data</a> on a related schema and are accumulated automatically when Central resolves the entity&#39;s foreign key relationships.</p><p>Related Data properties are displayed with a label indicating which relationship they come from:</p><blockquote><p><code>CompanyName (From CompanyId)</code></p></blockquote><p>Select these properties exactly as you would any other Central Property. The mapping engine reads the value from the entity&#39;s Related Data collection at sync time.</p><details class="details custom-block"><summary>When are Related Data properties available?</summary><p>Related Data properties only appear in the Central Property picker for <strong>save/subscribe</strong> actions. They are not available for read/publish actions because the data has not yet been accumulated at that point in the pipeline.</p><p>The list of available Related Data properties is determined by:</p><ul><li>The foreign key relationships defined on the entity&#39;s schema</li><li>Which properties on those related schemas have the <strong>Related Data</strong> flag enabled</li><li>Any Extra Primary Keys defined on the related schemas</li></ul><p>For a deeper explanation of how Related Data is accumulated and when to use it, see <a href="./reference-related-data.html">Related Data</a>.</p></details><h2 id="generated-value-mappings" tabindex="-1">Generated Value Mappings <a class="header-anchor" href="#generated-value-mappings" aria-label="Permalink to &quot;Generated Value Mappings&quot;">​</a></h2><p>When mapping a <strong>save/subscribe</strong> action, you can configure a field to produce its value at sync time rather than sourcing it from the entity. Use a <strong>Generated Value</strong> mapping when the connector requires a field that Central itself doesn&#39;t hold — a freshly minted password, an idempotency token, a per-sync timestamp, and so on.</p><p>Generated Values appear in the Mapping Type dropdown as a standard option, alongside Property, Primary Key, Fixed Value, etc. Select it, and a <strong>Generator</strong> picker appears with the following choices:</p><table tabindex="0"><thead><tr><th>Generator</th><th>What it produces</th></tr></thead><tbody><tr><td>New GUID</td><td>A fresh <code>Guid.NewGuid()</code> each time the map runs</td></tr><tr><td>Current Date/Time</td><td><code>DateTime.UtcNow</code> at the time of the save</td></tr><tr><td>Current Day / Month / Year</td><td>Integer components of the current date</td></tr></tbody></table><p>The generated value seeds the normal transform chain — you can run subsequent transforms on it (e.g. format a generated date, hash a generated GUID) just like any other source value.</p><p>Generated Value mappings are <strong>write-only</strong> — they are ignored on read actions, which prevents the generator from overwriting values coming back from the connector. They are also not offered inside MultiPropertyMap structures; add the Generated Value as a leaf map alongside other inner maps.</p><div class="tip custom-block"><p class="custom-block-title">Hiding generated secrets from logs</p><p>When the generated value is a credential (e.g. a password sent on account creation), select <strong>HideFromLogging</strong> in the map&#39;s Behaviors tab. The real value is still sent in the connector request, but appears as <code>[hidden]</code> in stored endpoint logs.</p></div><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>The Connector Property field still applies — it identifies <strong>where</strong> on the connector payload the generated value is written. The generator replaces the source (which would normally be the entity&#39;s field value), not the target.</p></div><h2 id="map-group-filters" tabindex="-1">Map Group Filters <a class="header-anchor" href="#map-group-filters" aria-label="Permalink to &quot;Map Group Filters&quot;">​</a></h2><p>Map Groups support configurable filters that control which data is processed during a sync. Filters are configured on the <strong>Filters</strong> tab when editing a Map Group.</p><p>A filter icon appears on Map Groups in the visual editor when filters are configured.</p><h3 id="how-filters-work" tabindex="-1">How Filters Work <a class="header-anchor" href="#how-filters-work" aria-label="Permalink to &quot;How Filters Work&quot;">​</a></h3><p>Filters use the same evaluation model as other filters in the platform — you define one or more <strong>filter groups</strong>, each containing one or more <strong>evaluations</strong>. Evaluations compare a property on the data model against a static value or a variable using operators like <code>=</code>, <code>!=</code>, <code>&gt;</code>, <code>&lt;</code>, <code>Is Blank</code>, <code>Not Blank</code>, and <code>Regex</code>.</p><ul><li><strong>Within a group</strong>, evaluations are chained with <strong>AND</strong> or <strong>OR</strong> (configurable per group).</li><li><strong>Between groups</strong>, groups are chained with <strong>AND</strong> or <strong>OR</strong> (configurable per group).</li></ul><h3 id="behavior-by-map-group-type" tabindex="-1">Behavior by Map Group Type <a class="header-anchor" href="#behavior-by-map-group-type" aria-label="Permalink to &quot;Behavior by Map Group Type&quot;">​</a></h3><p>The Filters tab displays contextual help text explaining the behavior:</p><table tabindex="0"><thead><tr><th>Map Group Type</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>Looping List</strong></td><td>Filters are evaluated against <strong>each item</strong> in the list. Items that do not pass are skipped — they will not be read into the model or written to the connector.</td></tr><tr><td><strong>Non-looping</strong></td><td>Filters are evaluated against <strong>the model</strong>. If the model does not pass, the entire Map Group is skipped.</td></tr></tbody></table><h3 id="filter-values" tabindex="-1">Filter Values <a class="header-anchor" href="#filter-values" aria-label="Permalink to &quot;Filter Values&quot;">​</a></h3><p>Evaluations support two value sources:</p><ul><li><strong>Static</strong> — a fixed value (e.g., <code>Active</code>, <code>1234</code>).</li><li><strong>Variable</strong> — a reference to an endpoint variable, evaluated at sync time (e.g., <code>{CurrentDate}</code>). Variables must be defined on the endpoint&#39;s <strong>Variables</strong> tab.</li></ul><h3 id="example-use-cases" tabindex="-1">Example Use Cases <a class="header-anchor" href="#example-use-cases" aria-label="Permalink to &quot;Example Use Cases&quot;">​</a></h3><ul><li><strong>Skip inactive line items on save:</strong> Add a Looping List filter where <code>Status = Active</code> to only write active items to the connector.</li><li><strong>Skip a Map Group for certain entity types:</strong> Add a filter on a non-looping Map Group where <code>Type = Booking</code> so the group only runs for booking entities.</li><li><strong>Filter by date using a variable:</strong> Add a filter where <code>ModifiedDate &gt; {LastSyncDate}</code> to only process recently changed items.</li></ul><h2 id="mapping-properties-of-endpoint-actions-per-protocol" tabindex="-1">Mapping Properties of Endpoint Actions per Protocol <a class="header-anchor" href="#mapping-properties-of-endpoint-actions-per-protocol" aria-label="Permalink to &quot;Mapping Properties of Endpoint Actions per Protocol&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>Users should be familiar with XPath to complete Read mapping.</p></div><h3 id="json-reads" tabindex="-1">JSON Reads <a class="header-anchor" href="#json-reads" aria-label="Permalink to &quot;JSON Reads&quot;">​</a></h3><p>All JSON Read maps use JSONPath for the Connector Property to tell the mapping engine where on the payload we should map the data from.</p><table tabindex="0"><thead><tr><th>Property Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Property</strong></td><td>Maps a single value in a JSON document to a property on your Schema.</td></tr><tr><td><strong>Multi-Property</strong></td><td>Generally used in tandem with a Transform, it takes multiple values on a JSON document, transforms those values in some way, and then sets the transformed result onto a property on your Schema.</td></tr><tr><td><strong>Looping List</strong></td><td>Used to bind an array on the connector JSON payload to a list of items on your schema. For example, a Looping List can be used to map the lines of a Sales Order or the Prices of an Item.</td></tr></tbody></table><h3 id="json-saves" tabindex="-1">JSON Saves <a class="header-anchor" href="#json-saves" aria-label="Permalink to &quot;JSON Saves&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Property</strong></td><td>Maps a single value on your schema to a property on the connector&#39;s JSON input.</td></tr><tr><td><strong>Multi-Property</strong></td><td>Generally used in tandem with a Transform, it can take multiple properties on your Schema and output a single property on the connector&#39;s JSON input.</td></tr><tr><td><strong>Nested Property</strong></td><td>Used to create a static JSON nested property. Usually used in tandem with another map that is embedded inside of it. For example, in this input: <code>{ &quot;customerName&quot;: { &quot;firstName&quot;:&quot;Marc&quot;, &quot;lastName&quot;:&quot;Johnson&quot;}}</code>, the nested Property would be &quot;customerName&quot;.</td></tr><tr><td><strong>Static List</strong></td><td>Used to create a static JSON array to insert static items, such as <code>&quot;itemPrices&quot;:[ {&quot;price&quot;: 23.12}]</code>.</td></tr><tr><td><strong>Looping List</strong></td><td>Used to bind a dynamic list of items on your Schema list to an array of items on the connector&#39;s JSON input.</td></tr></tbody></table><h3 id="xml-reads" tabindex="-1">XML Reads <a class="header-anchor" href="#xml-reads" aria-label="Permalink to &quot;XML Reads&quot;">​</a></h3><p>Uses XPath to map the data from the connector to your Schema. It is important to note that the first step in creating an XML Read Mapping is to add the root Element of the XML Document. For example, in a SOAP document, the root is typically <code>&lt;Envelope&gt;&lt;/Envelope&gt;</code>.</p><table tabindex="0"><thead><tr><th>Property Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Simple Element</strong></td><td>Maps a single value in an XML Element or XML Attribute to a property on your Schema. To map the first name value, enter &quot;FirstName.&quot; To map from a nested value (e.g. street), enter &quot;Address/Street.&quot; For an attribute, enter &quot;Person/@title.&quot;</td></tr><tr><td><strong>Multi-Element</strong></td><td>Generally used in tandem with a Transform, it can take multiple values on an XML document, transform those values in some way, and then sets the transformed result onto a property on your Schema (e.g. to combine a person&#39;s first name and last name).</td></tr><tr><td><strong>Looping List</strong></td><td>Used to map a list of repeating items in the connector XML document to a list of items on your Schema. For example, a Looping List can be used to map the phone numbers into a list on the Schema.</td></tr></tbody></table><details class="details custom-block"><summary>XML Syntax Example</summary><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Person</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> title</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Mr.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">FirstName</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;John&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">FirstName</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">LastName</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Doe&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">LastName</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Address</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Street</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;123 Main St&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Street</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Address</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">PhoneNumbers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">PhoneNumber</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;home&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;555-1212&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">PhoneNumber</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">PhoneNumber</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;work&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;555-2323&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">PhoneNumber</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">PhoneNumbers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Person</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div></details><h3 id="xml-saves" tabindex="-1">XML Saves <a class="header-anchor" href="#xml-saves" aria-label="Permalink to &quot;XML Saves&quot;">​</a></h3><p>On an XML Save, your maps will be used to build the XML document that gets sent to the Connector. Every layer of the XML document needs to be built and accounted for in your mapping. You will be mapping both structure and content.</p><table tabindex="0"><thead><tr><th>Property Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Element</strong></td><td>Adds an element to the XML with the value selected from the Schema.</td></tr><tr><td><strong>Attribute</strong></td><td>Attributes can be added to any Element and will map to the value selected in the Schema.</td></tr><tr><td><strong>Multi-Element</strong></td><td>Generally used in tandem with a Transform, it can take multiple properties on your Schema and output a single Element on the connector&#39;s XML input.</td></tr><tr><td><strong>Nested Element</strong></td><td>Used to create a static XML nested Element. Typically used in tandem with another map that is embedded inside of it. For example, in this input: <code>&lt;customerName&gt;&lt;firstName&gt;Marc&lt;/firstName&gt;&lt;lastName&gt;Johnson&lt;/lastName&gt;&lt;/customerName&gt;</code>, the nested Element would be <code>&lt;customerName&gt;</code>.</td></tr><tr><td><strong>Static List</strong></td><td>Used to create a static list of XML items where you can insert static items. For example: <code>&lt;itemPrices&gt;&lt;price&gt;23.12&lt;/price&gt;&lt;/itemPrices&gt;</code>.</td></tr><tr><td><strong>Looping List</strong></td><td>Used to bind a dynamic list of items on a list on your Schema, to a list of items on the connector&#39;s XML input.</td></tr></tbody></table><h3 id="sql-reads" tabindex="-1">SQL Reads <a class="header-anchor" href="#sql-reads" aria-label="Permalink to &quot;SQL Reads&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Column</strong></td><td>Maps a single value from a database to a property on your Schema.</td></tr><tr><td><strong>Multi-Property</strong></td><td>Generally used in tandem with a Transform, it can take multiple database columns, transform those values in some way, and then sets the transformed result onto a property on your Schema.</td></tr><tr><td><strong>Looping List</strong></td><td>Used to map child/line-item rows from a query result into a list property on your Schema. The query returns parent and child data together in a flat result set, and the engine groups rows by a parent identifier column.</td></tr></tbody></table><details class="details custom-block"><summary>SQL Looping List — How It Works</summary><p>Unlike JSON or XML where child data is nested inside the document structure, SQL result sets are flat — every row contains both parent-level and child-level columns. A Looping List tells the mapping engine how to reconstruct the parent/child hierarchy from that flat data.</p><p><strong>Reads:</strong> The engine groups all returned rows by the value in the <strong>Connector Property</strong> defined on the Looping List (the parent identifier column, e.g. <code>ShipmentID</code>). The first row in each group supplies the parent-level property values, and each row in the group creates a new item on the Schema list.</p><p><strong>Example:</strong> A query returns shipments with their packages:</p><table tabindex="0"><thead><tr><th>ShipmentID</th><th>ShipDate</th><th>PackageID</th><th>Height</th><th>Width</th></tr></thead><tbody><tr><td>SHP001</td><td>2026-01-15</td><td>PKG001</td><td>10</td><td>5</td></tr><tr><td>SHP001</td><td>2026-01-15</td><td>PKG002</td><td>15</td><td>10</td></tr><tr><td>SHP002</td><td>2026-01-20</td><td>PKG003</td><td>20</td><td>15</td></tr></tbody></table><p>With a Looping List whose Connector Property is <code>ShipmentID</code>, this produces two Shipment entities — <code>SHP001</code> with two Packages and <code>SHP002</code> with one Package.</p><p><strong>To set up a SQL Read Looping List:</strong></p><ol><li>Add a <strong>Looping List</strong> map group to your read action mapping.</li><li>Set the <strong>Connector Property</strong> to the column that identifies the parent record (e.g. <code>ShipmentID</code>).</li><li>Set the <strong>Central Property</strong> to the list property on your Schema (e.g. <code>Packages</code>).</li><li>Inside the Looping List, add Column maps for each child property (e.g. <code>PackageID</code>, <code>Height</code>, <code>Width</code>).</li><li>Add Column maps at the parent level (outside the Looping List) for parent-only properties (e.g. <code>ShipDate</code>).</li></ol></details><h3 id="sql-saves" tabindex="-1">SQL Saves <a class="header-anchor" href="#sql-saves" aria-label="Permalink to &quot;SQL Saves&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Property</strong></td><td>Maps a single value on your Schema to a column on a database.</td></tr><tr><td><strong>Multi-Property</strong></td><td>Generally used in tandem with a Transform, it can take multiple properties on your Schema and output a single column on the database.</td></tr></tbody></table><h3 id="file-reads" tabindex="-1">File Reads <a class="header-anchor" href="#file-reads" aria-label="Permalink to &quot;File Reads&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Column</strong></td><td>Maps a single value from a file to a property on your schema.</td></tr><tr><td><strong>Multi-Property</strong></td><td>Generally used in tandem with a Transform, it can take multiple file columns, transform those values in some way, and then set the transformed result onto a property on your Schema.</td></tr><tr><td><strong>Looping List</strong></td><td>Used to map child/line-item rows from a delimited file into a list property on your Schema. The file contains parent and child data together in flat rows, and the engine groups rows by a parent identifier column.</td></tr></tbody></table><h3 id="file-saves" tabindex="-1">File Saves <a class="header-anchor" href="#file-saves" aria-label="Permalink to &quot;File Saves&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Property</strong></td><td>Maps a single value on your Schema to a column on a character delimited file.</td></tr><tr><td><strong>Multi-Property</strong></td><td>Generally used in tandem with a Transform, it can take multiple properties on your Schema and output a single column on a file.</td></tr><tr><td><strong>Looping List</strong></td><td>Used to flatten a list of child items from your Schema into individual rows on the output file, with parent columns repeated on each row.</td></tr></tbody></table><details class="details custom-block"><summary>File Looping List — How It Works</summary><p>Delimited files (CSV, TSV, etc.) are inherently flat — there is no nesting. A Looping List tells the mapping engine how to reconstruct the parent/child hierarchy on reads, and how to flatten it back out on writes.</p><p><strong>Reads:</strong> The engine groups all rows in the file by the value in the <strong>Connector Property</strong> defined on the Looping List (the parent identifier column, e.g. <code>ShipmentID</code>). The first row in each group supplies the parent-level property values, and each row in the group creates a new item on the Schema list. This works identically to the SQL read behavior described above.</p><p><strong>Writes:</strong> The engine does the reverse — for each child item in the Schema list, it produces one row in the output file. Parent-level columns (mapped outside the Looping List) are repeated on every row alongside the child-level columns.</p><p><strong>Example:</strong> A CSV file containing shipments with their packages:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ShipmentID,ShipDate,PackageID,Height,Width</span></span>
<span class="line"><span>SHP001,2026-01-15,PKG001,10,5</span></span>
<span class="line"><span>SHP001,2026-01-15,PKG002,15,10</span></span>
<span class="line"><span>SHP002,2026-01-20,PKG003,20,15</span></span></code></pre></div><p>On <strong>read</strong>, this produces two Shipment entities — <code>SHP001</code> with two Packages and <code>SHP002</code> with one Package.</p><p>On <strong>write</strong>, a Shipment entity with two Packages produces two rows in the file, both sharing the same <code>ShipmentID</code> and <code>ShipDate</code> values.</p><p><strong>To set up a File Looping List:</strong></p><ol><li>Add a <strong>Looping List</strong> map group to your action mapping.</li><li>Set the <strong>Connector Property</strong> to the column that identifies the parent record (e.g. <code>ShipmentID</code>).</li><li>Set the <strong>Central Property</strong> to the list property on your Schema (e.g. <code>Packages</code>).</li><li>Inside the Looping List, add Column/Property maps for each child property (e.g. <code>PackageID</code>, <code>Height</code>, <code>Width</code>).</li><li>Add Column/Property maps at the parent level (outside the Looping List) for parent-only properties (e.g. <code>ShipDate</code>).</li></ol></details><h3 id="fixed-width-files" tabindex="-1">Fixed-Width Files <a class="header-anchor" href="#fixed-width-files" aria-label="Permalink to &quot;Fixed-Width Files&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Property</strong></td><td>Maps a fixed character length for each field.</td></tr></tbody></table><h2 id="map-preview" tabindex="-1">Map Preview <a class="header-anchor" href="#map-preview" aria-label="Permalink to &quot;Map Preview&quot;">​</a></h2><p><img src="`+s+'" alt="Map Preview Panel"></p><p>The <strong>Map Preview</strong> panel lets you test your mapping configuration against real data without running a full sync. It is available in the mapping editor for both read and write (save) directions.</p><p>To open it, select the <strong>Map Preview</strong> tab in the mapping editor.</p><h3 id="read-direction-publish" tabindex="-1">Read Direction (Publish) <a class="header-anchor" href="#read-direction-publish" aria-label="Permalink to &quot;Read Direction (Publish)&quot;">​</a></h3><p>The input for a read preview is a <strong>single connector record</strong> — one item from the payload your connector would return during a Get Changes or API Read call.</p><p><strong>To get test data:</strong></p><ol><li>Open the endpoint&#39;s action configuration and use the <strong>Test Request</strong> button to run a live connector call.</li><li>Copy a single record from the response body (not the full list).</li><li>Paste it into the Map Preview input panel.</li><li>Select <strong>Run Preview</strong> to see how your maps transform the connector data into a Common Model entity.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The output panel defaults to <strong>code view</strong> showing the raw mapped JSON. Use the toggle in the top right of the output panel to switch to <strong>tree view</strong> for a more readable field-by-field breakdown.</p></div><h3 id="write-direction-save-subscribe" tabindex="-1">Write Direction (Save / Subscribe) <a class="header-anchor" href="#write-direction-save-subscribe" aria-label="Permalink to &quot;Write Direction (Save / Subscribe)&quot;">​</a></h3><p>The input for a write preview is a <strong>Common Model entity message</strong> — representing data flowing from the Common Model out to your connector.</p><p><strong>To get test data:</strong></p><ul><li>Select <strong>Generate Input</strong> to automatically build a trimmed entity message pre-populated with the fields your maps reference. Edit the values directly in the editor to match a realistic record.</li><li>Alternatively, copy a message from the <strong>Monitoring</strong> screen (search for a recently processed message of the correct entity type) and paste it into the input panel.</li></ul><p>Use the <strong>Create / Update</strong> toggle to test both operation types — some maps behave differently depending on the operation.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>The generated input wraps the entity in an <code>EntityMessage</code> envelope (with <code>system</code>, <code>entityType</code>, and <code>payload</code>). This matches the format used internally by the sync engine, so what you test here is what the engine will actually receive.</p></div><h3 id="logs" tabindex="-1">Logs <a class="header-anchor" href="#logs" aria-label="Permalink to &quot;Logs&quot;">​</a></h3><p>After running a preview, select the <strong>Logs</strong> tab on the output panel to review any mapping warnings or errors reported by the engine.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./datahub-data-adaptation.html">Data Adaptation</a> — Transform and adapt data during mapping</li><li><a href="./datahub-endpoint-config.html">Endpoint Configuration</a> — Configure endpoint action inputs and parameterization</li><li><a href="./datahub-code-view.html">Code View</a> — View and edit the underlying mapping configuration</li><li><a href="./datahub-key-scraping.html">Key Scraping</a> — Configure how primary keys are indexed after saves</li></ul>',81)])])}const y=e(r,[["render",l]]);export{m as __pageData,y as default};
